    }

    .text-left { text-align: left; }

    .text-bold { font-weight: 700; }

    .text-muted { color: #7c7c7c; }

    .report-table table {
        width: 100%;
        table-layout: fixed;
        border-collapse: separate;
        border-spacing: 0;
    }

    .report-table th,
    .report-table td {
        padding: 6px 8px;
